const fs = require('fs');

const DATA_DIR = '/polybot-data';

function loadJson(name) {
  try { return JSON.parse(fs.readFileSync(`${DATA_DIR}/${name}`, 'utf8')); }
  catch { return null; }
}

function fmtUsd(v) { return `$${(v||0).toFixed(2)}`; }

const ctrl = loadJson('control.json');
const positions = loadJson('positions.json') || [];
const trades = loadJson('paper_trades.json') || [];
const spreadCtrl = loadJson('spread_control.json');
const spreadTrades = loadJson('spread_trades.json') || [];

const openPos = positions.filter(p => !p.resolved);
const resolved = positions.filter(p => p.resolved);

let msg = '📊 **Polybot 6h Report**\n\n';

if (ctrl) {
  msg += `Mode: **${ctrl.mode}** | Budget: ${fmtUsd(ctrl.daily_spent_usd)}/${fmtUsd(ctrl.daily_budget_usd)}\n`;
  msg += `Traders: ${(ctrl.enabled_traders||[]).join(', ')}\n`;
}

msg += `Open: ${openPos.length} positions`;
if (openPos.length) {
  const unreal = openPos.reduce((s,p) => s + (p.current_price-p.entry_price)*p.size, 0);
  msg += ` (${fmtUsd(unreal)} unrealised)`;
}
msg += '\n';

if (resolved.length) {
  const pnl = resolved.reduce((s,p) => s + (p.pnl||0), 0);
  const wins = resolved.filter(p => (p.pnl||0) > 0).length;
  msg += `Resolved: ${resolved.length} (${wins}W/${resolved.length-wins}L) PnL: ${fmtUsd(pnl)}\n`;
}

const now = new Date().toISOString().slice(0,10);
const todayTrades = trades.filter(t => (t.detected_at||'').startsWith(now));
msg += `Today: ${todayTrades.filter(t=>t.executed).length} executed, ${todayTrades.filter(t=>!t.executed).length} rejected\n`;

if (spreadCtrl) {
  msg += `\nSpreadbot: ${spreadCtrl.mode} | ${fmtUsd(spreadCtrl.daily_spent_usd||0)}/${fmtUsd(spreadCtrl.daily_budget_usd||0)}`;
  if (spreadTrades.length) {
    const spnl = spreadTrades.reduce((s,t) => s + (t.pnl||0), 0);
    msg += ` | PnL: ${fmtUsd(spnl)}`;
  }
  msg += '\n';
}

return [{ json: { message: msg } }];
